scwin.f_eventRadioClick = function (No) {
  let toDate = scwin.vToDate;
  let toYear = toDate.toString().substring(0, 4);
  let toMonth = toDate.toString().substring(4, 6);
  let toDay = toDate.toString().substring(6, 8);
  let toYearDt1, toYearDt2;
  let toMonthDt1, toMonthDt2;
  let toDayDt1, toDayDt2;
  let sDt1, sDt2;
  let NowDate = new Date(toYear, toMonth - 1, toDay);
  switch (No) {
    case '1':
      {
        scwin.gsVl3 = toDate;
        scwin.gsVl4 = toDate;
        break;
      }
    case '2':
      {
        let numb = NowDate.getTime();
        let TempDay = NowDate.getDay();
        let TempDate = NowDate;
        TempDate.setTime(numb - TempDay * 1000 * 60 * 60 * 24);
        toYearDt1 = TempDate.getFullYear();
        toMonthDt1 = TempDate.getMonth() + 1;
        toDayDt1 = TempDate.getDate();
        toMonthDt1 = '0' + toMonthDt1;
        toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
        toDayDt1 = '0' + toDayDt1;
        toDayDt1 = toDayDt1.substr(toDayDt1.length - 2, toDayDt1.length);
        sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();
        TempDate.setTime(numb + (6 - TempDay) * 1000 * 60 * 60 * 24);
        toYearDt2 = TempDate.getFullYear();
        toMonthDt2 = TempDate.getMonth() + 1;
        toDayDt2 = TempDate.getDate();
        toMonthDt2 = '0' + toMonthDt2;
        toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
        toDayDt2 = '0' + toDayDt2;
        toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
        sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();
        scwin.gsVl3 = sDt1;
        scwin.gsVl4 = sDt2;
        break;
      }
    case '3':
      {
        let numb = NowDate.getTime();
        let TempDate = NowDate;
        toMonthDt1 = NowDate.getMonth() + 1;
        toYearDt1 = TempDate.getFullYear();
        toMonthDt1 = '0' + toMonthDt1;
        toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
        toDayDt1 = '01';
        sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();
        TempDate = new Date(toYearDt1, TempDate.getMonth() + 1, toDayDt1);
        TempDate.setTime(TempDate.getTime() - 1 * 1000 * 60 * 60 * 24);
        toYearDt2 = TempDate.getFullYear();
        toMonthDt2 = TempDate.getMonth();
        toMonthDt2 = '0' + toMonthDt1;
        toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
        toDayDt2 = TempDate.getDate();
        toDayDt2 = '0' + toDayDt2;
        toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
        sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();
        scwin.gsVl3 = sDt1;
        scwin.gsVl4 = sDt2;
        break;
      }
    case '4':
      {
        let numb = NowDate.getTime();
        let TempDate = NowDate;
        toMonthDt1 = NowDate.getMonth();
        toYearDt1 = TempDate.getFullYear();
        toMonthDt1 = '0' + toMonthDt1;
        toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
        toDayDt1 = '01';
        sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();
        TempDate = new Date(toYearDt1, TempDate.getMonth(), toDayDt1);
        TempDate.setTime(TempDate.getTime() - 1 * 1000 * 60 * 60 * 24);
        toYearDt2 = TempDate.getFullYear();
        toMonthDt2 = TempDate.getMonth();
        toMonthDt2 = '0' + toMonthDt1;
        toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
        toDayDt2 = TempDate.getDate();
        toDayDt2 = '0' + toDayDt2;
        toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
        sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();
        scwin.gsVl3 = sDt1;
        scwin.gsVl4 = sDt2;
        break;
      }
    case '5':
      {
        break;
      }
  }
};
scwin.search_cargo = async function () {
  scwin.f_eventRadioClick(dma_cond.get('cargoDateTyp'));
  let condObj = {};
  condObj.cargoDateTyp = dma_cond.get('cargoDateTyp');
  condObj.cargoDateCnd = dma_cond.get('cargoDateCnd');
  if (dma_cond.get('cargoDateTyp') == 5) {
    condObj.cargoDate1 = dma_cond.get('cargoDate1');
    condObj.cargoDate2 = dma_cond.get('cargoDate2');
  } else {
    condObj.cargoDate1 = scwin.gsVl3.trim();
    condObj.cargoDate2 = scwin.gsVl4.trim();
  }
  condObj.cargoSrchTyp = dma_cond.get('cargoSrchTyp');
  condObj.cargoSrchCnd = dma_cond.get('cargoSrchCnd');
  condObj.cargoSts1 = dma_cond.get('cargoSts1');
  condObj.cargoSts2 = dma_cond.get('cargoSts2');
  condObj.cargoSts3 = dma_cond.get('cargoSts3');
  condObj.cargoHdidx = dma_cond.get('cargoHdidx');
  condObj.cargoBhidx = dma_cond.get('cargoBhidx');
  condObj.cargoOfcidx = dma_cond.get('cargoOfcidx');
  let ord = 0;
  condObj.cargoOrd1 = dma_cond.get('cargoOrd1');
  condObj.cargoOrdAsc1 = dma_cond.get('cargoOrdAsc1');
  condObj.cargoOrdUsr1 = dma_cond.get('cargoOrdUsr1');
  condObj.cargoOrd2 = dma_cond.get('cargoOrd2');
  condObj.cargoOrdAsc2 = dma_cond.get('cargoOrdAsc2');
  condObj.cargoOrdUsr2 = dma_cond.get('cargoOrdUsr2');
  condObj.cargoOrd3 = dma_cond.get('cargoOrd3');
  condObj.cargoOrdAsc3 = dma_cond.get('cargoOrdAsc3');
  condObj.cargoOrdUsr3 = dma_cond.get('cargoOrdUsr3');
  condObj.cargoSellClntNo = dma_cond.get('cargoSellClntNo');
  if (dma_cond.get('cargoOrdUsr1') > 0) {
    ord += 1;
  }
  if (dma_cond.get('cargoOrdUsr2') > 0) {
    ord += 2;
  }
  if (dma_cond.get('cargoOrdUsr3') > 0) {
    ord += 4;
  }
  condObj.ord = ord;
  condObj.caridx = scwin.ez110Idx;
  for (let key in condObj) {
    dma_cond.set(key, condObj[key]);
  }
  await $c.sbm.execute($p, sbm_RetrieveBlk);
};
