scwin.searchSwitch = async function (str) {
  if (str == 'cargo') {
    await scwin.search_cargo();
    scwin.CargoType = "cargo";
  } else if (str == 'cont') {
    await scwin.search_cont();
    scwin.CargoType = "cont";
  }
};
