scwin.cancelop = async function () {
  if (scwin.selectedLclRow == '') {
    await $c.win.alert($p, "화물 정보가 선택되지 않았습니다.");
    return;
  }
  let chk = await $c.win.confirm($p, "배차를 취소하시겠습니까?");
  if (chk) {
    let vFlIdxs;
    let vFlFlag;
    let vUserId;
    let RowCount = 0;
    if (scwin.CargoType == 'cargo') {
      vFlFlag = '1';
    } else {
      vFlFlag = '2';
    }
    vFlIdxs = '';
    if (vFlFlag == '1') {
      for (RowCount = 0; RowCount < ds_fl.getRowCount(); RowCount++) {
        if (ds_fl.getRowStatus(RowCount) == 'C' || gr_fl.getCheckedIndex().indexOf(RowCount) >= 0) {
          vFlIdxs += ds_fl.getCellData(RowCount, "idx") + ',';
        }
      }
    } else {
      for (RowCount = 0; RowCount < ds_flc.getRowCount(); RowCount++) {
        if (ds_flc.getRowStatus(RowCount) == 'C' || gr_flc.getCheckedIndex().indexOf(RowCount) >= 0) {
          vFlIdxs += ds_flc.getCellData(RowCount, "idx") + ',';
        }
      }
    }
    vFlIdxs = vFlIdxs.substring(0, vFlIdxs.length - 1);
    ds_ApplyAlloccarCancel.removeAll();
    vUserId = scwin.gUserId;
    let loop = vFlIdxs.replace(/-/g, ",");
    loop = loop.split(",");
    for (let i = 1; i < loop.length; i += 2) {
      let newRow = ds_ApplyAlloccarCancel.insertRow();
      ds_ApplyAlloccarCancel.setCellData(newRow, "flIdxs", loop[i]);
      ds_ApplyAlloccarCancel.setCellData(newRow, "flFlag", vFlFlag);
      ds_ApplyAlloccarCancel.setCellData(newRow, "flDtlIdxs", loop[i + 1]);
      ds_ApplyAlloccarCancel.setCellData(newRow, "userId", vUserId);
    }
    await $c.sbm.execute($p, sbm_ApplyAlloccarCancel);
    await scwin.reflashdata();
  }
};
scwin.deletefl = async function () {
  if (scwin.selectedLclRow == "") {
    await $c.win.alert($p, "화물 정보가 선택되지 않았습니다.");
    return;
  }
  let chk = await $c.win.confirm($p, "선택한 화물을 삭제하시겠습니까?");
  if (chk) {
    let vFlIdxs;
    let vFlFlag;
    let vDmOrdNo;
    let RowCount;
    if (scwin.CargoType == 'cargo') {
      vFlFlag = '1';
    } else {
      vFlFlag = '2';
    }
    vFlIdxs = '';
    vDmOrdNo = '';
    if (vFlFlag == '1') {
      for (RowCount = 0; RowCount < ds_fl.getRowCount(); RowCount++) {
        if (gr_fl.getCheckedIndex().indexOf(RowCount) >= 0) {
          vFlIdxs += ds_fl.getCellData(RowCount, "idx") + ',';
          vDmOrdNo += ds_fl.getCellData(RowCount, "dmOrdNo") + ',';
          if (ds_fl.getCellData(RowCount, "statuss") != '대기') {
            await $c.win.alert($p, '[TMS오류]배차된 화물을 삭제할 수 없습니다. 배차 취소 후 삭제 가능합니다.');
            await scwin.reflashdata();
            return;
          }
        }
      }
    } else {
      for (RowCount = 0; RowCount < ds_flc.getRowCount(); RowCount++) {
        if (gr_flc.getCheckedIndex().indexOf(RowCount) >= 0) {
          vFlIdxs += ds_flc.getCellData(RowCount, "idx") + ',';
          vDmOrdNo += ds_flc.getCellData(RowCount, "dmOrdNo") + ',';
          if (ds_flc.getCellData(RowCount, "statuss") != '대기') {
            await $c.win.alert($p, '[TMS오류]배차된 화물을 삭제할 수 없습니다. 배차 취소 후 삭제 가능합니다.');
            await scwin.reflashdata();
            return;
          }
        }
      }
    }
    vFlIdxs = vFlIdxs.substring(0, vFlIdxs.length - 1);
    vDmOrdNo = vDmOrdNo.substring(0, vDmOrdNo.length - 1);
    ds_AlloccarFlDelete.removeAll();
    let loop = vFlIdxs.replace(/-/g, ",");
    loop = loop.split(",");
    vDmOrdNo = vDmOrdNo.split(",");
    for (let i = 1; i < loop.length; i += 2) {
      let DmNoCoudnt = 0;
      let newRow = ds_AlloccarFlDelete.insertRow();
      ds_AlloccarFlDelete.setCellData(newRow, "flIdxs", loop[i]);
      ds_AlloccarFlDelete.setCellData(newRow, "flDtlIdxs", loop[i + 1]);
      ds_AlloccarFlDelete.setCellData(newRow, "flFlag", vFlFlag);
      ds_AlloccarFlDelete.setCellData(newRow, "dmOrdNo", vDmOrdNo[DmNoCoudnt]);
      DmNoCoudnt++;
    }
    await $c.sbm.execute($p, sbm_AlloccarFlDelete);
    await scwin.reflashdata();
  }
};
