scwin.f_print = async function (gubun) {
  let v_odrNo;
  if (gubun == 1) {
    if (ds_fl.getRowCount() == 0 || ds_fl.getRowPosition() < 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, new Array("오더"));
      return;
    }
    v_odrNo = ds_fl.getCellData(ds_fl.getRowPosition(), "dmOrdNo");
    let v_coshippingNo = ds_fl.getCellData(ds_fl.getRowPosition(), "dmCoshippingNo");
    if ($c.gus.cfIsNull($p, v_odrNo)) {
      await $c.gus.cfAlertMsg($p, "오더를 선택하십시요");
      return;
    }
    let odiParam = new ODIParam("tn_304_02_01b1");
    odiParam.add("ODR_NO", v_odrNo);
    odiParam.add("COSHIPPING_NO", v_coshippingNo);
    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.zoom", "100");
    $c.gus.cfOZPreview($p, "/ds/op/wrkplan/transwrkplan/tn_304_02_01b.ozr", odiParam, viewerParam, formParam);
  } else if (gubun == 2) {
    if (ds_flc.getRowCount() == 0 || ds_flc.getRowPosition() < 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, new Array("오더"));
      return;
    }
    v_odrNo = ds_flc.getCellData(ds_flc.getRowPosition(), "dmOrdNo");
    if ($c.gus.cfIsNull($p, v_odrNo)) {
      await $c.gus.cfAlertMsg($p, "오더를 선택하십시요");
      return;
    }
    let odiParam = new ODIParam("op_202_02_03r");
    odiParam.add("odrNo", v_odrNo);
    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.zoom", "100");
    $c.gus.cfOZPreview($p, "/ds/op/wrkplan/transwrkplan/op_202_02_03r.ozr", odiParam, viewerParam, formParam);
  } else if (gubun == 3) {
    let rmk2 = ds_fl.getCellData(ds_fl.getRowPosition(), 'rmk2');
    let param = "RMK2=" + rmk2;
    window.open("/ui/bp/fbp/op/ac/ez_208_01_02p.xml?" + param, "오서상세정보", "width=540,height=640");
  }
};
scwin.f_ediPreInfo = async function (row) {
  scwin.f_getTime();
  if (scwin.currTime > "1730" && (ds_flc.getCellData(row, "dptWrkPlCd") == "6C01" || ds_flc.getCellData(row, "arvWrkPlCd") == "6C01")) {
    await $c.win.alert($p, "17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
    return false;
  }
  if (ds_flc.getRowCount() == 0) return;
  if (ds_flc.getCellData(row, "vehclNo") == "") {
    await $c.gus.cfAlertMsg($p, "운송차량이 없습니다");
    return false;
  }
  if (ds_flc.getCellData(row, "dmOrd") == "") {
    await $c.gus.cfAlertMsg($p, "동부오더가 아닙니다");
    return false;
  } else {
    let odrNo = ds_flc.getCellData(row, "odrNo");
    let cntrSeq = ds_flc.getCellData(row, "cntrSeq");
    let wrkPathSeq = ds_flc.getCellData(row, "wrkPathSeq");
    let wrkStpSeq = ds_flc.getCellData(row, "wrkStpSeq");
    let wrkStpCd = ds_flc.getCellData(row, "wrkStpCd");
    let dptWrkPlCd = ds_flc.getCellData(row, "dptWrkPlCd");
    let arvWrkPlCd = ds_flc.getCellData(row, "arvWrkPlCd");
    let odrNoSub = odrNo.substring(1, 3);
    if (dptWrkPlCd == "6C01" || arvWrkPlCd == "6C01") {
      if (odrNoSub == "C2" && wrkStpCd == "0002" && wrkStpSeq == "20") {
        dma_edi.set("odrNo", odrNo);
        dma_edi.set("cntrSeq", cntrSeq);
        dma_edi.set("wrkPathSeq", wrkPathSeq);
        dma_edi.set("wrkStpSeq", wrkStpSeq);
        await $c.sbm.execute($p, sbm_edi);
      } else {
        await $c.win.alert($p, "수입 풀반출 이외에는 직접 COPINO전송을 할수없습니다.\n동부 담당 배차게 문의요망!!");
        return false;
      }
    }
    dma_edi.set("odrNo", odrNo);
    dma_edi.set("cntrSeq", cntrSeq);
    dma_edi.set("wrkPathSeq", wrkPathSeq);
    dma_edi.set("wrkStpSeq", wrkStpSeq);
    await $c.sbm.execute($p, sbm_edi);
  }
};
